//vip.opstream10.com/20220524/16620_58ab56e1/index.m3u8"}]}],"time":"","description":"<p>kể về những cuộc phiêu lưu, nghịch phá của Shaun và đàn cừu trên đồng cỏ của nông trại. Do sở hữu lượng IQ cao hơn cả người thường và bộ óc hiếu kỳ của một đứa trẻ lên ba, nên đôi khi, Shaun trở thành kẻ giật dây cho nhiều âm mưu “quậy phá” như: đặt bánh pizza, đào hồ bơi, biến kho thóc thành sàn nhảy lớn, ồn ào. Và xuyên suốt hành trình “tội ác” còn có sự đóng góp đáng kể của: Shirley - một cô cừu béo nhất bầy đàn có thể ăn bất cứ thứ gì mà cô nhìn thấy, Timmy - một bé cừu dễ thương; Bitzer - chú chó chăn cừu rất biết cư xử.</p>","tmdb":{"type":"tv","id":"3902","season":1,"vote_average":7.634,"vote_count":268},"modified":"2022-05-31T17:27:23.000Z","_image_preserved":true},{"id":"6296502e7a956fb5dbf3a03a","_id":"6296502e7a956fb5dbf3a03a","title":"Trái Tim Trong Lửa Lạnh","origin_name":"Duang Jai Nai Fai Nhao","slug":"trai-tim-trong-lua-lanh","year":2018,"type":"series","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a2318e0fc277084dfd77a","name":"Thái Lan","slug":"thai-lan"}],"lang_key":"Thuyết Minh","episode_current":"Tập 22","quality":"HD","is_4k":false,"is_exclusive":false,"status":"ongoing","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Thuyết Minh #1","server_data":[{"name":"1","slug":"1","filename":"trai-tim-trong-lua-lanh-thuyet-minh-duang-jai-nai-fai-nhao-tap-1","link_embed":"https://vip.opstream10.com/share/53ac2d01e41ff949c11c916309ae17b7","link_m3u8":"https://vip.opstream10.com/20220523/16529_5be42773/index.m3u8"},{"name":"2","slug":"2","filename":"trai-tim-trong-lua-lanh-thuyet-minh-duang-jai-nai-fai-nhao-tap-2","link_embed":"https://vip.opstream10.com/share/1de6c74e347052d6f145ad434acdc86f","link_m3u8":"https://vip.opstream10.com/20220523/16530_e8799b71/index.m3u8"},{"name":"3","slug":"3","filename":"t